String runWithTimeout(java.util.concurrent.Callable<String> task) {
    java.util.concurrent.ExecutorService ex = java.util.concurrent.Executors.newSingleThreadExecutor();
    java.util.concurrent.Future<String> f = ex.submit(task);
    try {
        return f.get(500, java.util.concurrent.TimeUnit.MILLISECONDS);
    } catch (java.util.concurrent.TimeoutException e) {
        f.cancel(true);
        return "TIMEOUT";
    } catch (Exception e) {
        return "ERROR";
    } finally {
        ex.shutdownNow();
    }
}

